import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Pricing",
  subtitle: "Flexible, transparent pricing for organizations of all sizes. Choose the plan that fits your security needs.",
  sections: [
    {
      title: "Pricing Plans",
      description: "Start free and scale as you grow. All plans include core security features with no hidden fees.",
      gridClass: "pricing-grid",
      grid: [
        {
          title: "Starter",
          description: "Perfect for small businesses and startups getting started with security.",
          price: "$0",
          period: "/month",
          list: [
            "5 security checks",
            "Basic threat detection",
            "Email support",
            "1 user",
            "1 cloud account",
            "Weekly scans"
          ],
          cta: { text: "Start Free", link: "/register" }
        },
        {
          title: "Professional",
          description: "Advanced security for growing organizations.",
          price: "$299",
          period: "/month",
          popular: true,
          list: [
            "100+ security checks",
            "AI-powered threat detection",
            "Priority support",
            "10 users",
            "5 cloud accounts",
            "Daily scans",
            "Compliance reports",
            "Real-time alerts"
          ],
          cta: { text: "Start Trial", link: "/register" }
        },
        {
          title: "Enterprise",
          description: "Full-spectrum security for large organizations.",
          price: "Custom",
          period: "",
          list: [
            "500+ security checks",
            "Advanced AI detection",
            "Dedicated support",
            "Unlimited users",
            "Unlimited cloud accounts",
            "Continuous monitoring",
            "Custom integrations",
            "SLA guarantee",
            "On-premise deployment"
          ],
          cta: { text: "Contact Sales", link: "/contact" }
        }
      ]
    },
    {
      title: "Compare Plans",
      description: "Detailed comparison of all features across plans.",
      table: {
        headers: ["Feature", "Starter", "Professional", "Enterprise"],
        rows: [
          ["Security Checks", "5", "100+", "500+"],
          ["AI Threat Detection", "Basic", "Advanced", "Full AI"],
          ["Compliance Reports", "Manual", "Automated", "Custom"],
          ["Real-time Alerts", "Email", "Email + SMS", "Multi-channel"],
          ["API Access", "-", "Full API", "Full API"],
          ["SSO Integration", "-", "✓", "✓"],
          ["SLA Guarantee", "-", "99.9%", "99.99%"],
          ["Support", "Email", "Priority 24/7", "Dedicated CSM"],
          ["Custom Integrations", "-", "10", "Unlimited"]
        ]
      }
    },
    {
      title: "Frequently Asked Questions",
      description: "",
      grid: true,
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Can I change plans anytime?",
          description: "Yes, you can upgrade or downgrade your plan at any time. Changes take effect immediately, and we'll prorate any payments."
        },
        {
          title: "What payment methods do you accept?",
          description: "We accept all major credit cards, ACH/wire transfers, and purchase orders for Enterprise customers."
        },
        {
          title: "Is there a free trial?",
          description: "Yes! All paid plans include a 14-day free trial with full access to all features. No credit card required to start."
        },
        {
          title: "Do you offer discounts for non-profits?",
          description: "Yes, we offer 50% discount for registered non-profit organizations and educational institutions."
        }
      ]
    }
  ],
  color: "#10b981"
};

function Pricing() {
  return <InfoPageLayout {...pageData} />;
}

export default Pricing;
